#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_fc_main, vUv ).xyz;

    // mix in code based off of Geiss's
    float pic = texture(sampler_noise_hq, vUvOriginal*uAspect.xy*.5+.1*roam_cos+.1*uTime).xyz;
    float lum = lum(pic);
    float use_it = abs(lum+.25 - (0.5+roam_cos.xy*0.15));
    float LFNoise = texture(sampler_noise_hq, pic-(vUv.yx*8 + (uTime*.15)));
    use_it = (1-use_it - (20*LFNoise));
    float tex = mix(ret, pic, use_it.xxx)*1;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q13         && ret.x<= q24*q11        )ret.y -= (noise9).x*.5;
if(ret.y> q22*q11         && ret.y<= q25*q12        )ret.z -= (noise9).y*.5;
if(ret.z> q23*q12         && ret.z<= q26*q13        )ret.x -= (noise9).z*.5;
ret=tex;
    // darken (decay) over uTime
    ret *= 0.95; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vUv = 0.05 + 0.9*vUv;

    // equivalent of a laplacian: [center*4 - each of the 4 neighbors*1]
    ret = 0;
    ret += texture(sampler_main, vUv ).xyz;
    ret += .25*GetBlur1(vUv);

    vec2 uv_echo;
    uv_echo.x = (vUv.y - 0.5)*(-1) + 0.5;
    uv_echo.y = vUv.x;

    vec3 ret2;
    ret2 = texture(sampler_main, uv_echo ).xyz;
    ret2 += .25*GetBlur1(uv_echo);

    vec2 uv_echo2;
    uv_echo2.y = (vUv.x - 0.5)*(-1) + 0.5;
    uv_echo2.x = vUv.y;

    vec3 ret3;
    ret3 = texture(sampler_main, uv_echo2 ).xyz;
    ret3 += .25* GetBlur1(uv_echo2);

    vec2 uv_echo3;
    uv_echo3 = (vUv - 0.5)*vec2(-1,-1) + 0.5;

    vec3 ret4;
    ret4 = texture(sampler_main, uv_echo3 ).xyz;
    ret4 += .25*GetBlur1(uv_echo3);


    ret = mix(0.5*mix(ret3,ret4,.5),0.5*mix(ret,ret2,.5),.5);
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((uv_echo2.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q13         && ret.x<= q23*q11        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q11         && ret.y<= q22*q12        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q12         && ret.z<= q21*q13        )ret.y -= (noise9).z*.5;

    // little bit of noise:
    ret *= 1 + 0.05*(texture(sampler_noise_lq, rand_frame.xy
           + vUv*uTexSize.xy*texsize_noise_lq.zw).xxx*2-1);

    // palettize:
    ret = pow(ret, vec3(0.5, 0.5, 0.7));

    ret = (ret-0.1)*2;
ret *= ret;
ret *= 7.2575654;
ret = pow(ret,1-ret);
    //ret.xyz *= 2; // a little bit of overbright

  fragColor = ret;
}
